import json
import re

# Load the business data
with open(locals()['var_function-call-17894049240398946376'], 'r') as f:
    businesses = json.load(f)

category_counts = {}
category_business_ids = {}

separators = ["services in ", "including ", "destination for ", "fields of "]

for b in businesses:
    desc = b.get('description', '')
    if not desc:
        continue

    # Find the start of the category list
    start_index = -1
    best_sep_len = 0

    for sep in separators:
        idx = desc.rfind(sep)
        if idx != -1:
            # We want the end of the separator
            current_start = idx + len(sep)
            if current_start > start_index:
                start_index = current_start

    if start_index != -1:
        cat_str = desc[start_index:]
        # Remove trailing period if exists
        if cat_str.endswith('.'):
            cat_str = cat_str[:-1]

        # Split by comma
        raw_cats = cat_str.split(',')
        cleaned_cats = []
        for i, raw_cat in enumerate(raw_cats):
            c = raw_cat.strip()
            # Handle "and " for the last element
            if i == len(raw_cats) - 1 and c.startswith('and '):
                c = c[4:].strip()
            if c:
                cleaned_cats.append(c)

        for cat in cleaned_cats:
            category_counts[cat] = category_counts.get(cat, 0) + 1
            if cat not in category_business_ids:
                category_business_ids[cat] = []
            category_business_ids[cat].append(b['business_id'])

# Find top category
if category_counts:
    top_category = max(category_counts, key=category_counts.get)
    count = category_counts[top_category]
    ids = category_business_ids[top_category]
else:
    top_category = None
    count = 0
    ids = []

result = {
    "top_category": top_category,
    "count": count,
    "business_ids": ids
}

print("__RESULT__:")
print(json.dumps(result))

